features.snippet:
// extern module parameterized on data width
extern module ExternMod #(parameter int DW = 2) (
    input  logic          clk,
    input  logic [DW-1:0] data_in
);

module top (
    input logic       clk,
    input logic [5:0] data_in
);
    ExternMod #(.DW(2)) inst_a (.clk(clk), .data_in(data_in[1:0]));
    ExternMod #(.DW(4)) inst_b (.clk(clk), .data_in(data_in[5:2]));
endmodule

module Wrapper #(parameter int DW = 4) (
    input  logic          clk,
    input  logic [DW-1:0] data_in
);
endmodule

module dut (
    input logic       clk,
    input logic [5:0] bus
);
    Wrapper #(.DW(2)) u0 (.clk(clk), .data_in(bus[1:0]));
    Wrapper #(.DW(4)) u1 (.clk(clk), .data_in(bus[5:2]));
endmodule
